/* ── PDF article attachment ─────────────────────────────────────────────────
   The existing "Night Changes" entry in the Notion Writing DB has its body
   replaced by the Graduation Article PDF, rasterized to page images under
   public/writing/graduation-article/ (regenerate: `npm run render:graduation`).
   The writing modal detects the `pdf` field and renders the stacked pages
   instead of the Notion blocks. */
const NIGHT_CHANGES_PDF = {
  basePath: "/writing/graduation-article",
  ext: "webp",
  pageCount: 4,
  aspect: 0.7834, // page width / height — reserves space so images don't reflow
};

const normalizeTitle = (t) => String(t ?? "").trim().toLowerCase();
const isNightChanges = (piece) =>
  normalizeTitle(piece.title) === "night changes" || piece.id === "night-changes";

// Stand-in used only when the live Notion list isn't available (local dev with
// no env), so the PDF piece is still reachable in the archive + by slug.
const NIGHT_CHANGES_FALLBACK = {
  id: "night-changes",
  title: "Night Changes",
  type: "Journalism",
  publication: "Print Feature",
  date: "",
  excerpt: "A printed feature, reproduced here exactly as it ran in print.",
  featured: false,
  position: null,
  pos: null,
  rotation: 0,
  z: 0,
  pages: NIGHT_CHANGES_PDF.pageCount,
  tags: [],
  _order: 0,
  blocks: [],
  pdf: NIGHT_CHANGES_PDF,
};

// Attaches the PDF body to the "Night Changes" piece (matched by title or
// slug). If the list has no such piece (fallback path), appends the stand-in
// so the PDF stays viewable. Idempotent.
export function withPdfArticles(list = []) {
  let matched = false;
  const out = list.map((piece) => {
    if (!isNightChanges(piece)) return piece;
    matched = true;
    return piece.pdf ? piece : { ...piece, pdf: NIGHT_CHANGES_PDF };
  });
  if (!matched) out.push(NIGHT_CHANGES_FALLBACK);
  return out;
}
